package main

import (
	"bufio"
	"errors"
	"fmt"
	"os"
	"strconv"
	"strings"
)

type Vector struct {
	data     []int
	size     int
	capacity int
}

func NewVector(capacity int) *Vector {
	return &Vector{
		data:     make([]int, 0, capacity), // nunca use len(data) ou cap(data) ou qq método do go de manipulação de array
		size:     0,
		capacity: capacity,
	}
}

func (v *Vector) Status() string {
	return fmt.Sprintf("size:%v capacity:%v", v.size, v.capacity)
}

func (v *Vector) PopBack() error {
	if v.size == 0 {
		return errors.New("vector is empty")
	}
	v.data = v.data[:v.size-1]
	v.size--
	return nil
}

func (v *Vector) PushBack(value int) {
	if v.size == v.capacity {
		v.capacity *= 2
	}
	v.data = append(v.data, value)
	v.size++
}

func (v *Vector) Reserve(newCapacity int) {
	if v.capacity > newCapacity {
		return
	}
	v.capacity = newCapacity
}

func (v *Vector) String() string {
	string := ""
	string += fmt.Sprintf("[")
	for i := 0; i < v.size; i++ {
		if i < v.size-1 {
			string += fmt.Sprintf("%v, ", v.data[i])
		} else {
			string += fmt.Sprintf("%v", v.data[i])
		}
	}
	string += fmt.Sprintf("]\n")
	return string
}

func FormatSlice(s []int) string {
	str := "["
	for i, v := range s {
		if i < len(s)-1 {
			str += fmt.Sprintf("%v, ", v)
		} else {
			str += fmt.Sprintf("%v", v)
		}
	}
	str += "]"
	return str
}

func (v *Vector) In_Range(i int) bool {
	return i < v.size
}

func (v *Vector) At(index int) (int, error) {
	if !v.In_Range(index) {
		return 0, errors.New("index out of range")
	}
	return v.data[index], nil
}

func (v *Vector) Set(index int, value int) error {
	if !v.In_Range(index) {
		return errors.New("index out of range")
	}
	v.data[index] = value
	return nil
}

func (v *Vector) Insert(index int, value int) error {
	if index < 0 || index > v.size {
		return errors.New("index out of range")
	}
	if v.size == v.capacity {
		newCap := v.capacity * 2
		if newCap == 0 {
			newCap = 1
		}
		v.Reserve(newCap)
	}
	v.data = append(v.data, 0)

	for i := v.size; i > index; i-- {
		v.data[i] = v.data[i-1]
	}
	v.data[index] = value
	v.size++
	return nil
}

func (v *Vector) IndexOf(value int) int {
	for i := 0; i < v.size; i++ {
		if v.data[i] == value {
			return i
		}
	}
	return -1
}

func (v *Vector) Contains(value int) bool {
	return v.IndexOf(value) != -1
}

func (v *Vector) Erase(index int) error {
	if !v.In_Range(index) {
		return errors.New("index out of range")
	}
	for i := index; i < v.size-1; i++ {
		v.data[i] = v.data[i+1]
	}
	v.data = v.data[:v.size-1]
	v.size--
	return nil
}

func (v *Vector) Slice(start, end int) []int {
	if start < 0 {
		start = v.size + start
	}
	if end < 0 {
		end = v.size + end
	}
	start = start % v.size
	end = end % v.size

	if start <= end {
		return v.data[start:end]
	}

	length := start - end
	saida := make([]int, length)
	for i := 0; i < length; i++ {
		saida[i] = v.data[start-1-i]
	}
	return saida
}

func (v *Vector) Clear() {
	if v.size == 0 {
		return
	}
	v.data = nil
	v.size = 0
}

func (v *Vector) Capacity() int {
	return v.capacity
}

func Join(slice []int, sep string) string {
	if len(slice) == 0 {
		return ""
	}
	var result strings.Builder
	fmt.Fprintf(&result, "%d", slice[0])
	for _, value := range slice[1:] {
		fmt.Fprintf(&result, "%s%d", sep, value)
	}
	return result.String()
}

func main() {
	var line, cmd string
	scanner := bufio.NewScanner(os.Stdin)

	v := NewVector(0)
	for {
		fmt.Print("$")
		if !scanner.Scan() {
			break
		}
		line = scanner.Text()
		fmt.Println(line)
		parts := strings.Fields(line)
		if len(parts) == 0 {
			continue
		}
		cmd = parts[0]

		switch cmd {
		case "end":
			return
		case "init":
			value, _ := strconv.Atoi(parts[1])
			v = NewVector(value)
		case "push":
			for _, part := range parts[1:] {
				value, _ := strconv.Atoi(part)
				v.PushBack(value)
			}
		case "show":
			fmt.Print(v.String())
		case "status":
			fmt.Println(v.Status())
		case "pop":
			err := v.PopBack()
			if err != nil {
				fmt.Println(err)
			}
		case "insert":
			index, _ := strconv.Atoi(parts[1])
			value, _ := strconv.Atoi(parts[2])
			err := v.Insert(index, value)
			if err != nil {
				fmt.Println(err)
			}
		case "erase":
			index, _ := strconv.Atoi(parts[1])
			err := v.Erase(index)
			if err != nil {
				fmt.Println(err)
			}
		case "indexOf":
			value, _ := strconv.Atoi(parts[1])
			index := v.IndexOf(value)
			fmt.Println(index)
		case "contains":
			value, _ := strconv.Atoi(parts[1])
			if v.Contains(value) {
				fmt.Println("true")
			} else {
				fmt.Println("false")
			}
		case "clear":
			v.Clear()
		case "capacity":
			fmt.Println(v.Capacity())
		case "get":
			index, _ := strconv.Atoi(parts[1])
			value, err := v.At(index)
			if err != nil {
				fmt.Println(err)
			} else {
				fmt.Println(value)
			}
		case "set":
			index, _ := strconv.Atoi(parts[1])
			value, _ := strconv.Atoi(parts[2])
			err := v.Set(index, value)
			if err != nil {
				fmt.Println(err)
			}
		case "reserve":
			newCapacity, _ := strconv.Atoi(parts[1])
			v.Reserve(newCapacity)
		case "slice":
			start, _ := strconv.Atoi(parts[1])
			end, _ := strconv.Atoi(parts[2])
			slice := v.Slice(start, end)
			fmt.Println(FormatSlice(slice))
		default:
			fmt.Println("fail: comando invalido")
		}
	}
}
